DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "contextForm.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $x = list_random('a' .. 'k', 'm', 'n', 'p' .. 'r', 't' .. 'z'); Context("Form")->variables->are($x => 'Real'); $b = random(2,5); $m = random(2,4); $n = random(2,9); $bm = $b**$m; $total = $m*$n; $given = Formula("($b $x^$n)^$m"); $ans = Formula("$bm $x^$total");
############################################################ # Body ############################################################
BEGIN_PGML Use the properties of exponents to simplify the expression.
[`[$given]`]
[_]{$ans}{6}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION This expression is a product of two things ([`[$b]`] and [`[$x]^{[$n]}`]) that is then raised to a power. We can raise each of the two factors to that outer power instead:
[```[$b]^{[$m]}\left([$x]^{[$n]}\right)^{[$m]}```]
and then use the power-to-power property of exponents to simplify it more: [`[$ans]\text{.}`]
END_PGML_SOLUTION
